public string ToString(string? format, IFormatProvider? formatProvider = null)
{
    format ??= "0.## ";
    formatProvider ??= CultureInfo.CurrentCulture;

    if (!format.Contains('#') && !format.Contains('0'))
    {
        format = "0.## " + format;
    }

    if (format.Contains("#.##", StringComparison.Ordinal))
    {
        format = format.Replace("#.##", "0.##");
    }

    if (format.Contains(TerabyteSymbol, StringComparison.OrdinalIgnoreCase))
        return Terabytes.ToString(format.Replace(TerabyteSymbol, "TB", StringComparison.OrdinalIgnoreCase), formatProvider);

    if (format.Contains(GigabyteSymbol, StringComparison.OrdinalIgnoreCase))
        return Gigabytes.ToString(format.Replace(GigabyteSymbol, "GB", StringComparison.OrdinalIgnoreCase), formatProvider);

    if (format.Contains(MegabyteSymbol, StringComparison.OrdinalIgnoreCase))
        return Megabytes.ToString(format.Replace(MegabyteSymbol, "MB", StringComparison.OrdinalIgnoreCase), formatProvider);

    if (format.Contains(KilobyteSymbol, StringComparison.OrdinalIgnoreCase))
        return Kilobytes.ToString(format.Replace(KilobyteSymbol, "KB", StringComparison.OrdinalIgnoreCase), formatProvider);

    if (format.Contains(ByteSymbol, StringComparison.Ordinal))
        return Bytes.ToString(format.Replace(ByteSymbol, "B"), formatProvider);

    if (format.Contains(BitSymbol, StringComparison.Ordinal))
        return ((double)Bits).ToString(format.Replace(BitSymbol, "b"), formatProvider);

    var (value, symbol) = GetLargestWholeUnit();
    return $"{value.ToString(format, formatProvider)} {symbol}";
}

